'use strict';

var data = require('./data.js');

class I18nCache {
    #countriesLocales = new Map();
    #translations = new Map();
    initialize(srcPath) {
        this.#countriesLocales = data.createCountriesLocales();
        this.#translations = data.createTranslations(srcPath);
    }
    getLocale(countryId) {
        return this.#countriesLocales.get(countryId);
    }
    getTranslations(locale) {
        const translations = this.#translations.get(locale);
        if (translations) {
            return translations;
        }
        const [language] = locale.split('-');
        return this.#translations.get(language) ?? {};
    }
}
const i18nCache = new I18nCache();

exports.i18nCache = i18nCache;
